'use strict';

// Spawned as a detached background process by daemon.js start()

const path  = require('path');
const fs    = require('fs');
const { CONFIG_DIR } = require('./config');
const { tick, PROJECT_PATH } = require('./daemon');

const PID_FILE = path.join(CONFIG_DIR, 'daemon.pid');
const LOG_FILE = path.join(CONFIG_DIR, 'daemon.log');

fs.mkdirSync(CONFIG_DIR, { recursive: true });
fs.writeFileSync(PID_FILE, String(process.pid), 'utf8');

// Redirect stdout/stderr to log file so we can inspect daemon activity
const logStream = fs.createWriteStream(LOG_FILE, { flags: 'a' });
const origWrite = (chunk) => logStream.write(`[${new Date().toISOString()}] ${chunk}`);
process.stdout.write = origWrite;
process.stderr.write = origWrite;

console.log(`[daemon-worker] started, tracking project: ${PROJECT_PATH}`);

process.on('SIGTERM', () => {
  try { fs.unlinkSync(PID_FILE); } catch {}
  process.exit(0);
});

async function loop() {
  try { await tick(); } catch (e) { console.error('[daemon-worker] tick error:', e.message); }
  setTimeout(loop, 5 * 60 * 1000);
}

loop();
